import sys
from functools import lru_cache
input = sys.stdin.readline

def solve():
    n = int(input())
    A = list(map(int, input().split()))

    @lru_cache(maxsize=None)
    def dp(l, r, last):
        # Returns True if current player wins
        if l > r:
            return False
        can_left = A[l] > last
        can_right = A[r] > last
        if not can_left and not can_right:
            return False
        if can_left and not dp(l+1, r, A[l]):
            return True
        if can_right and not dp(l, r-1, A[r]):
            return True
        return False

    if dp(0, n-1, -1):
        print("Alice")
    else:
        print("Bob")

solve()

